function Accordion() {
  const [open, setOpen] = React.useState(false);

  return (
    <div style={{ padding: '40px', fontFamily: 'sans-serif', color: '#e0e0e0', background: '#16213e', borderRadius: '8px', maxWidth: '420px', margin: '40px auto' }}>
      <button onClick={() => setOpen(!open)} style={{ padding: '8px 16px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>
        Toggle details
      </button>
      {/* BUG: the panel is always shown — it should appear only when open is true */}
      <p data-testid="panel" style={{ marginTop: '16px' }}>Hidden details revealed!</p>
    </div>
  );
}
